"use client";

import { Bell, Search, Globe, Shield } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { ThemeToggle } from "@/components/theme-toggle";
import { Badge } from "@/components/ui/badge";
import { useEnv } from "@/components/env-provider";

export function Navbar() {
  const { state } = useEnv();

  const lastObs = state?.history?.[state.history.length - 1]?.observation;
  const tenantId = String(
    (lastObs?.extra_context as Record<string, unknown> | undefined)?.tenant_id ?? "Global"
  );

  return (
    <header className="sticky top-0 z-30 flex h-16 w-full items-center justify-between border-b bg-background/80 px-6 backdrop-blur-sm">
      <div className="flex items-center gap-4">
        <div className="flex items-center gap-3">
          <Badge variant="outline" className="rounded-full bg-indigo-50 text-indigo-700 border-indigo-200 gap-1 px-3">
             <Globe className="h-3 w-3" />
             {state?.scenario_name || "Production"}
          </Badge>
          <Badge variant="outline" className="rounded-full bg-amber-50 text-amber-700 border-amber-200 gap-1 px-3">
             <Shield className="h-3 w-3" />
             Tenant: {tenantId}
          </Badge>
        </div>
      </div>

      <div className="flex items-center gap-4">
        <div className="relative hidden lg:flex items-center group cursor-pointer" onClick={() => {}}>
          <Search className="absolute left-3 h-4 w-4 text-muted-foreground group-hover:text-primary transition-colors" />
          <div className="flex h-9 w-64 items-center justify-between rounded-md border border-border/50 bg-muted/30 pl-9 pr-3 text-sm text-muted-foreground shadow-sm transition-colors group-hover:border-primary/50 group-hover:bg-background">
            <span>Search global commands...</span>
            <kbd className="pointer-events-none inline-flex h-5 select-none items-center gap-1 rounded border border-border/50 bg-muted px-1.5 font-mono text-[10px] font-medium opacity-100">
              <span className="text-xs">⌘</span>K
            </kbd>
          </div>
        </div>

        <Button variant="ghost" size="icon" className="relative rounded-full">
          <Bell className="h-5 w-5" />
          {lastObs?.chaos_incident && (
            <span className="absolute top-1.5 right-1.5 h-2 w-2 rounded-full bg-destructive animate-ping" />
          )}
        </Button>
        <ThemeToggle />
      </div>
    </header>
  );
}
